codeExample:
student = {"name": "Alice", "age": 25, "grade": "A"}

# Keys and values
for key, value in student.items():
    print(f"{key}: {value}")

# Just values
print("\nValues only:")
for v in student.values():
    print(v)

# Dictionary comprehension
squares = {x: x**2 for x in range(5)}
print("\nSquares:", squares)
